from flask import Flask, request, jsonify
import redis
import os
import ssl

app = Flask(__name__)

# Redis connection settings
REDIS_NODES = [
    {"host": "redis-node-1", "port": 6379},
    {"host": "redis-node-2", "port": 6379},
    {"host": "redis-node-3", "port": 6379},
]

# Create a Redis connection pool
def create_redis_connection():
    return redis.RedisCluster(
        startup_nodes=REDIS_NODES,
        ssl=True,
        ssl_cert_reqs=ssl.CERT_REQUIRED,
        decode_responses=True
    )

redis_client = create_redis_connection()

@app.route('/store_token', methods=['POST'])
def store_token():
    data = request.json
    user_id = data.get('user_id')
    token = data.get('token')
    ttl = data.get('ttl', 3600)  # Default TTL of 1 hour

    if not user_id or not token:
        return jsonify({"error": "user_id and token are required"}), 400

    redis_client.setex(f"user_token:{user_id}", ttl, token)
    return jsonify({"message": "Token stored successfully"}), 201

@app.route('/get_token/<user_id>', methods=['GET'])
def get_token(user_id):
    token = redis_client.get(f"user_token:{user_id}")
    if token is None:
        return jsonify({"error": "Token not found"}), 404
    return jsonify({"token": token}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)